import esp32
from micropython import const
import bluetooth

# Define constants for BLE services and characteristics
ESP_SVC = const(0x180F)  # ESP32 Service
SENSOR_DATA_CHR = const(0x2A3D)  # Sensor Data Characteristic
CONTROL_CMD_CHR = const(0x2A3E)  # Control Command Characteristic

# Initialize BLE GATT server
server = bluetooth.BluetoothServer()

# Add ESP32 service to the BLE GATT server
esp32_service = server.addService(ESP_SVC)

# Add characteristics for sensor data and control commands to the ESP32 service
sensor_data_chr = esp32_service.addCharacteristic(SENSOR_DATA_CHR)
control_cmd_chr = esp32_service.addCharacteristic(CONTROL_CMD_CHR)

# Set the permissions for each characteristic
sensor_data_chr.setPermission(bluetooth.GATT_PERM_READ, bluetooth.GATT_AUTH_NONE)
control_cmd_chr.setPermission(bluetooth.GATT_PERM_WRITE, bluetooth.GATT_AUTH_NONE)

# Start the BLE GATT server
server.start()